export function getAllVocabulary() {
  return week34.days.flatMap((day, dayIndex) =>
    (day.vocabulary || []).map((word, wordIndex) => ({
      ...word,
      id: `w34-d${dayIndex + 1}-${wordIndex}`,
      dayId: day.id,
      dayTitle: day.title,
    }))
  )
}
